        "path": "dead-cells-trainer/Program.cs",
        "content": "using DeadCellsTrainer.Core;\nusing DeadCellsTrainer.Memory;\nusing Serilog;\n\nnamespace DeadCellsTrainer;\n\n/// <summary>\n/// Entry point for the Dead Cells trainer application.\n/// Initializes logging, memory reader, and trainer core.\n/// </summary>\npublic class Program\n{\n    public static async Task Main(string[] args)\n    {\n        // Configure Serilog for console and file logging\n        Log.Logger = new LoggerConfiguration()\n            .WriteTo.Console()\n            .WriteTo.File(\"logs/trainer-.log\", rollingInterval: RollingInterval.Day)\n            .MinimumLevel.Information()\n            .CreateLogger();\n\n        try\n        {\n            Log.Information(\"Dead Cells Trainer starting...\");\n\n            // Attempt to find the Dead Cells process\n            var processFinder = new ProcessFinder(\"DeadCells\");\n            var process = processFinder.FindProcess();\n\n            if (process == null)\n            {\n                Log.Error(\"Dead Cells process not found. Please start the game first.\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n                return;\n            }\n\n            Log.Information(\"Attached to Dead Cells process (PID: {Pid})\", process.Id);\n\n            // Initialize memory reader and trainer core\n            var memoryReader = new MemoryReader(process);\n            var trainerCore = new TrainerCore(memoryReader);\n\n            // Start the main trainer loop\n            await trainerCore.RunAsync();\n        }\n        catch (Exception ex)\n        {\n            Log.Fatal(ex, \"Trainer encountered a fatal error\");\n        }\n        finally\n        {\n            Log.CloseAndFlush();\n        }\n    }\n}\n"
    },
