        "path": "dead-cells-trainer/Core/TrainerCore.cs",
        "content": "using DeadCellsTrainer.Memory;\nusing Serilog;\n\nnamespace DeadCellsTrainer.Core;\n\n/// <summary>\n/// Core trainer logic that manages cheats and user interaction.\n/// Provides methods to modify in-game values like health, gold, and stats.\n/// </summary>\npublic class TrainerCore\n{\n    private readonly MemoryReader _memoryReader;\n    private readonly CancellationTokenSource _cts;\n\n    // Known memory offsets for Dead Cells (example offsets, not actual)\n    // These would be discovered via tools like Cheat Engine\n    private const int HealthOffset = 0x00A1B2C0;\n    private const int GoldOffset = 0x00A1B2D0;\n    private const int StrengthOffset = 0x00A1B2E0;\n\n    public TrainerCore(MemoryReader memoryReader)\n    {\n        _memoryReader = memoryReader ?? throw new ArgumentNullException(nameof(memoryReader));\n        _cts = new CancellationTokenSource();\n    }\n\n    /// <summary>\n    /// Runs the trainer loop, listening for keyboard input to toggle cheats.\n    /// </summary>\n    public async Task RunAsync()\n    {\n        Log.Information(\"Trainer running. Press F1 for infinite health, F2 for max gold, F3 for max strength, Escape to exit.\");\n\n        while (!_cts.Token.IsCancellationRequested)\n        {\n            if (Console.KeyAvailable)\n            {\n                var key = Console.ReadKey(true).Key;\n                switch (key)\n                {\n                    case ConsoleKey.F1:\n                        await SetInfiniteHealthAsync();\n                        break;\n                    case ConsoleKey.F2:\n                        await SetMaxGoldAsync();\n                        break;\n                    case ConsoleKey.F3:\n                        await SetMaxStrengthAsync();\n                        break;\n                    case ConsoleKey.Escape:\n                        Log.Information(\"Trainer shutting down...\");\n                        _cts.Cancel();\n                        break;\n                }\n            }\n\n            // Small delay to reduce CPU usage\n            await Task.Delay(100, _cts.Token);\n        }\n    }\n\n    /// <summary>\n    /// Sets the player's health to a very high value (9999).\n    /// </summary>\n    private async Task SetInfiniteHealthAsync()\n    {\n        try\n        {\n            await _memoryReader.WriteInt32Async(HealthOffset, 9999);\n            Log.Information(\"Infinite health activated (Health = 9999)\");\n        }\n        catch (Exception ex)\n        {\n            Log.Error(ex, \"Failed to set infinite health\");\n        }\n    }\n\n    /// <summary>\n    /// Sets the player's gold to maximum (999999).\n    /// </summary>\n    private async Task SetMaxGoldAsync()\n    {\n        try\n        {\n            await _memoryReader.WriteInt32Async(GoldOffset, 999999);\n            Log.Information(\"Max gold activated (Gold = 999999)\");\n        }\n        catch (Exception ex)\n        {\n            Log.Error(ex, \"Failed to set max gold\");\n        }\n    }\n\n    /// <summary>\n    /// Sets the player's strength stat to maximum (999).\n    /// </summary>\n    private async Task SetMaxStrengthAsync()\n    {\n        try\n        {\n            await _memoryReader.WriteInt32Async(StrengthOffset, 999);\n            Log.Information(\"Max strength activated (Strength = 999)\");\n        }\n        catch (Exception ex)\n        {\n            Log.Error(ex, \"Failed to set max strength\");\n        }\n    }\n\n    /// <summary>\n    /// Disposes resources and stops the trainer loop.\n    /// </summary>\n    public void Dispose()\n    {\n        _cts.Cancel();\n        _cts.Dispose();\n        _memoryReader.Dispose();\n    }\n}\n"
    },
