        "path": "dead-cells-trainer/Memory/MemoryReader.cs",
        "content": "using System.Diagnostics;\nusing System.Runtime.InteropServices;\nusing Serilog;\n\nnamespace DeadCellsTrainer.Memory;\n\n/// <summary>\n/// Provides low-level memory reading and writing capabilities for a target process.\n/// Uses Windows API functions (ReadProcessMemory, WriteProcessMemory).\n/// </summary>\npublic class MemoryReader : IDisposable\n{\n    private readonly Process _process;\n    private readonly IntPtr _processHandle;\n    private bool _disposed;\n\n    // Windows API imports\n    [DllImport(\"kernel32.dll\", SetLastError = true)]\n    private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n    [DllImport(\"kernel32.dll\", SetLastError = true)]\n    private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n    [DllImport(\"kernel32.dll\", SetLastError = true)]\n    private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n    [DllImport(\"kernel32.dll\", SetLastError = true)]\n    private static extern bool CloseHandle(IntPtr hObject);\n\n    // Process access flags\n    private const uint PROCESS_VM_READ = 0x0010;\n    private const uint PROCESS_VM_WRITE = 0x0020;\n    private const uint PROCESS_VM_OPERATION = 0x0008;\n    private const uint PROCESS_QUERY_INFORMATION = 0x0400;\n\n    /// <summary>\n    /// Initializes a new instance of the MemoryReader class.\n    /// </summary>\n    /// <param name=\"process\">The target process to interact with.</param>\n    public MemoryReader(Process process)\n    {\n        _process = process ?? throw new ArgumentNullException(nameof(process));\n        _processHandle = OpenProcess(PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION | PROCESS_QUERY_INFORMATION, false, _process.Id);\n        \n        if (_processHandle == IntPtr.Zero)\n        {\n            throw new InvalidOperationException($\"Failed to open process handle. Error code: {Marshal.GetLastWin32Error()}\");\n        }\n\n        Log.Information(\"Memory reader initialized for process {ProcessName} (PID: {Pid})\", _process.ProcessName, _process.Id);\n    }\n\n    /// <summary>\n    /// Reads an integer (4 bytes) from the specified memory address.\n    /// </summary>\n    /// <param name=\"address\">The memory address to read from.</param>\n    /// <returns>The integer value read from memory.</returns>\n    public async Task<int> ReadInt32Async(int address)\n    {\n        return await Task.Run(() =>\n        {\n            var buffer = new byte[4];\n            if (ReadProcessMemory(_processHandle, (IntPtr)address, buffer, buffer.Length, out int bytesRead) && bytesRead == 4)\n            {\n                return BitConverter.ToInt32(buffer, 0);\n            }\n            Log.Warning(\"Failed to read memory at address 0x{Address:X8}\", address);\n            return 0;\n        });\n    }\n\n    /// <summary>\n    /// Writes an integer (4 bytes) to the specified memory address.\n    /// </summary>\n    /// <param name=\"address\">The memory address to write to.</param>\n    /// <param name=\"value\">The integer value to write.</param>\n    public async Task WriteInt32Async(int address, int value)\n    {\n        await Task.Run(() =>\n        {\n            var buffer = BitConverter.GetBytes(value);\n            if (WriteProcessMemory(_processHandle, (IntPtr)address, buffer, buffer.Length, out int bytesWritten) && bytesWritten == 4)\n            {\n                Log.Debug(\"Written value {Value} to address 0x{Address:X8}\", value, address);\n            }\n            else\n            {\n                Log.Warning(\"Failed to write memory at address 0x{Address:X8}\", address);\n            }\n        });\n    }\n\n    /// <summary>\n    /// Disposes the memory reader and closes the process handle.\n    /// </summary>\n    public void Dispose()\n    {\n        if (!_disposed)\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                Log.Information(\"Process handle closed\");\n            }\n            _disposed = true;\n        }\n    }\n}\n"
    },
