        "path": "dead-cells-trainer/Memory/ProcessFinder.cs",
        "content": "using System.Diagnostics;\nusing Serilog;\n\nnamespace DeadCellsTrainer.Memory;\n\n/// <summary>\n/// Utility class to find a running process by name.\n/// </summary>\npublic class ProcessFinder\n{\n    private readonly string _processName;\n\n    /// <summary>\n    /// Initializes a new instance of the ProcessFinder class.\n    /// </summary>\n    /// <param name=\"processName\">The name of the process to find (without extension).</param>\n    public ProcessFinder(string processName)\n    {\n        _processName = processName ?? throw new ArgumentNullException(nameof(processName));\n    }\n\n    /// <summary>\n    /// Attempts to find a running process with the specified name.\n    /// </summary>\n    /// <returns>The first matching Process object, or null if not found.</returns>\n    public Process? FindProcess()\n    {\n        try\n        {\n            var processes = Process.GetProcessesByName(_processName);\n            if (processes.Length > 0)\n            {\n                var process = processes[0];\n                Log.Information(\"Found process {ProcessName} with PID {Pid}\", _processName, process.Id);\n                return process;\n            }\n            else\n            {\n                Log.Warning(\"Process {ProcessName} not found\", _processName);\n                return null;\n            }\n        }\n        catch (Exception ex)\n        {\n            Log.Error(ex, \"Error while searching for process {ProcessName}\", _processName);\n            return null;\n        }\n    }\n}\n"
    },
