        "content": "using DeadCellsTrainer.Memory;\nusing Moq;\nusing System.Diagnostics;\n\nnamespace DeadCellsTrainer.Tests;\n\n/// <summary>\n/// Unit tests for MemoryReader class.\n/// Uses Moq to mock process interactions.\n/// </summary>\n[TestClass]\npublic class MemoryReaderTests\n{\n    private Mock<Process> _mockProcess;\n\n    [TestInitialize]\n    public void Setup()\n    {\n        _mockProcess = new Mock<Process>();\n        _mockProcess.Setup(p => p.Id).Returns(12345);\n        _mockProcess.Setup(p => p.ProcessName).Returns(\"DeadCells\");\n    }\n\n    [TestMethod]\n    [ExpectedException(typeof(ArgumentNullException))]\n    public void Constructor_NullProcess_ThrowsArgumentNullException()\n    {\n        // Arrange & Act & Assert\n        var reader = new MemoryReader(null);\n    }\n\n    [TestMethod]\n    public void Constructor_ValidProcess_CreatesInstance()\n    {\n        // This test would normally require a real process handle; here we just verify the constructor logic\n        // For unit testing, we'd mock OpenProcess, but that's complex due to P/Invoke\n        // This is a placeholder to show test structure\n        Assert.IsNotNull(_mockProcess.Object);\n    }\n\n    [TestMethod]\n    public async Task ReadInt32Async_ValidAddress_ReturnsValue()\n    {\n        // Since MemoryReader uses P/Invoke, proper unit testing would require a test harness\n        // or integration test. This demonstrates the intended test pattern.\n        // Skipping actual implementation due to external dependency.\n        await Task.CompletedTask;\n        Assert.IsTrue(true);\n    }\n\n    [TestMethod]\n    public async Task WriteInt32Async_ValidAddress_WritesValue()\n    {\n        // Placeholder for integration test\n        await Task.CompletedTask;\n        Assert.IsTrue(true);\n    }\n\n    [TestMethod]\n    public void Dispose_MultipleCalls_DoesNotThrow()\n    {\n        // Test that Dispose can be called multiple times safely\n        // In a real test, we'd create an instance and call Dispose twice\n        Assert.IsTrue(true);\n    }\n}\n"
